      '<div class="rp-region-name">' + escHtml(regionName) + '</div>' +
      '<div class="rp-region-meta">' + escHtml(countryName) +
        (code ? ' · ' + escHtml(code) : '') + '</div>' +
    '</div>' +
    '<button class="rp-close" onclick="closeRegionPanel()">\u00d7</button>';

  // Body
  var html = '';

